    20→static inline uint32_t f2u(float f)
    21→{
    22→    union { float f; uint32_t u; } x;
    23→    x.f = f;
    24→    return x.u;
    25→}
    26→
    27→static inline float u2f(uint32_t u)
    28→{
    29→    union { float f; uint32_t u; } x;
    30→    x.u = u;
    31→    return x.f;
    32→}
    33→
    34→static volatile float g_acc;
    35→
    36→static void emit(float x)
    37→{
    38→#ifdef EN_PERF
    39→    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    40→    g_acc += coshf(vx);
    41→#else
    42→    float r = coshf(x);
    43→    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
    44→#endif
    45→}
    46→
    47→static void emit_u(uint32_t bits)
    48→{
    49→    emit(u2f(bits));
    50→}
    51→
    52→/* ------------------------------------------------------------------ */
    53→/* Representative 100-point test                                       */
    54→/* ------------------------------------------------------------------ */
    55→
    56→static void test_representative_100(void)
    57→{
    58→    /* --- Section 1: Special IEEE 754 values (7) --- */
    59→    emit(0.0f);
    60→    emit(-0.0f);
    61→    emit_u(0x7fc00000u);  /* qNaN */
    62→    emit_u(0x7f800001u);  /* sNaN */
    63→    emit_u(0xffc00000u);  /* -qNaN */
    64→    emit_u(0x7f800000u);  /* +Inf */
    65→    emit_u(0xff800000u);  /* -Inf */
    66→
    67→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    68→    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    69→    emit_u(0x80000001u);  /* min negative subnormal */
    70→    emit_u(0x00400000u);  /* mid subnormal */
    71→    emit_u(0x80400000u);  /* mid negative subnormal */
    72→    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    73→    emit_u(0x807fffffu);  /* max negative subnormal */
    74→
    75→    /* --- Section 3: Normal boundary values (6) --- */
    76→    emit(FLT_MIN);                /* smallest normal: 2^-126 = 0x00800000 */
    77→    emit(-FLT_MIN);
    78→    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    79→    emit_u(0x7f7fffffu);          /* FLT_MAX */
    80→    emit_u(0xff7fffffu);          /* -FLT_MAX */
    81→    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */
    82→
    83→    /* --- Section 4: Near 1.0 (ULP density) (8) --- */
    84→    emit_u(0x3f7fffffu);          /* one ULP below 1.0 */
    85→    emit(1.0f);
    86→    emit_u(0x3f800001u);          /* one ULP above 1.0 */
    87→    emit_u(0x3f7ffff0u);          /* a few ULPs below 1.0 */
    88→    emit_u(0x3f800010u);          /* a few ULPs above 1.0 */
    89→    emit(-1.0f);
    90→    emit_u(0xbf7fffffu);          /* one ULP toward zero from -1.0 */
    91→    emit_u(0xbf800001u);          /* one ULP away from zero from -1.0 */
    92→
    93→    /* --- Section 5: Exponent switching points (6) --- */
    94→    emit_u(0x3f000000u);          /* 0.5 */
    95→    emit_u(0x3f000001u);          /* one ULP above 0.5 */
    96→    emit_u(0x40000000u);          /* 2.0 */
    97→    emit_u(0x3fffffffu);          /* one ULP below 2.0 */
    98→    emit_u(0x40800000u);          /* 4.0 */
    99→    emit_u(0x3e800000u);          /* 0.25 */
   100→
   101→    /* --- Section 6: Hyperbolic-specific mathematical constants (14) --- */
   102→    /* cosh is even, so cosh(x) == cosh(-x); test both signs */
   103→    emit_u(0x3f317218u);          /* ln2 ~ 0.6931: cosh(ln2) = 1.25 exactly */
   104→    emit_u(0xbf317218u);          /* -ln2 */
   105→    emit(0.5f);                   /* cosh(0.5) ~ 1.1276 */
   106→    emit(-0.5f);
   107→    emit(1.5f);                   /* cosh(1.5) ~ 2.3524 */
   108→    emit(-1.5f);
   109→    emit(2.0f);                   /* cosh(2) ~ 3.7622 */
   110→    emit(-2.0f);
   111→    emit_u(0x3f490fdbu);          /* pi/4 ~ 0.7854 */
   112→    emit_u(0xbf490fdbu);          /* -pi/4 */
   113→    emit_u(0x3fc90fdbu);          /* pi/2 ~ 1.5708 */
   114→    emit_u(0xbfc90fdbu);          /* -pi/2 */
   115→    emit_u(0x40490fdbu);          /* pi ~ 3.1416 */
   116→    emit_u(0xc0490fdbu);          /* -pi */
   117→
   118→    /* --- Section 7: Overflow threshold ULP neighbors (8) --- */
   119→    /* coshf overflows near x ~ 88.7229 (0x42b17218) */
   120→    emit_u(0x42b17217u);          /* one ULP below overflow threshold */
   121→    emit_u(0x42b17218u);          /* exp overflow threshold ~ 88.7229 */
   122→    emit_u(0x42b17219u);          /* one ULP above overflow threshold */
   123→    emit_u(0x42b17210u);          /* a few ULPs below threshold */
   124→    emit_u(0xc2b17217u);          /* negative: one ULP above -threshold */
   125→    emit_u(0xc2b17218u);          /* -threshold */
   126→    emit_u(0xc2b17219u);          /* one ULP below -threshold */
   127→    emit_u(0xc2b17210u);          /* a few ULPs below -threshold */
   128→
   129→    /* --- Section 8: Large arguments near overflow (8) --- */
   130→    emit(10.0f);
   131→    emit(-10.0f);
   132→    emit(20.0f);
   133→    emit(-20.0f);
   134→    emit(50.0f);
   135→    emit(80.0f);
   136→    emit(88.0f);
   137→    emit(-88.0f);
   138→
   139→    /* --- Section 9: Small-argument fast-path (cosh(x)~1) (8) --- */
   140→    /* For tiny x, cosh(x) = 1 + x^2/2 + ...; test power-of-2 thresholds */
   141→    emit_u(0x39800000u);          /* 2^-12 ~ 2.44e-4 */
   142→    emit_u(0xb9800000u);          /* -2^-12 */
   143→    emit_u(0x3d800000u);          /* 2^-4 = 0.0625 */
   144→    emit_u(0xbd800000u);          /* -2^-4 */
   145→    emit_u(0x33800000u);          /* 2^-24 ~ 5.96e-8, near epsilon */
   146→    emit_u(0xb3800000u);          /* -2^-24 */
   147→    emit(1.0e-20f);
   148→    emit(-1.0e-20f);
   149→
   150→    /* --- Section 10: Hard and branch-coverage cases (29) --- */
   151→    /* Eighth-interval boundaries */
   152→    emit(0.125f);
   153→    emit(-0.125f);
   154→    emit(0.25f);
   155→    emit(-0.25f);
   156→    emit(0.375f);
   157→    emit(-0.375f);
   158→    emit(0.625f);
   159→    emit(-0.625f);
   160→    emit(0.75f);
   161→    emit(-0.75f);
   162→    emit(0.875f);
   163→    emit(-0.875f);
   164→    /* Mid-range polynomial stress */
   165→    emit(3.0f);
   166→    emit(-3.0f);
   167→    emit(4.0f);
   168→    emit(-4.0f);
   169→    emit(5.0f);
   170→    emit(-5.0f);
   171→    emit(8.0f);
   172→    emit(-8.0f);
   173→    emit(16.0f);
   174→    emit(-16.0f);
   175→    emit(64.0f);
   176→    emit(-64.0f);
   177→    /* Just past overflow -- result is +Inf */
   178→    emit(100.0f);
   179→    emit(-100.0f);
   180→    emit_u(0x7f7fffffu);          /* FLT_MAX: guaranteed overflow */
   181→    emit_u(0xff7fffffu);          /* -FLT_MAX */
   182→    /* Near-zero boundary: 1 ULP above zero */
   183→    emit_u(0x00000002u);          /* 2 * min subnormal */
   184→}
