   186→/* ------------------------------------------------------------------ */
   187→/* Dense sweep and exhaustive small (accuracy path only)              */
   188→/* ------------------------------------------------------------------ */
   189→
   190→#ifndef EN_PERF
   191→/* Sweep [0, 88.7] and [-88.7, 0] in 200 steps each */
   192→static void test_sweep(void)
   193→{
   194→    float hi = 88.7f;
   195→    int nsteps = 200;
   196→    float step = hi / (float)nsteps;
   197→
   198→    for (int i = 0; i <= nsteps; i++)
   199→        emit((float)i * step);
   200→
   201→    for (int i = 0; i <= nsteps; i++)
   202→        emit(-hi + (float)i * step);
   203→}
   204→
   205→/* Sample [0, 1] every 4194304 ULP (~250 cases) */
   206→static void test_exhaustive_small(void)
   207→{
   208→    uint32_t end = 0x3f800000u; /* 1.0 */
   209→    for (uint32_t b = 0; b <= end; b += 4194304)
   210→        emit_u(b);
   211→}
   212→#endif /* !EN_PERF */
   213→
   214→/* ------------------------------------------------------------------ */
